<?php
 namespace League\CommonMark\Reference; use League\CommonMark\Normalizer\TextNormalizer; final class ReferenceMap implements ReferenceMapInterface { private $normalizer; private $references = []; public function __construct() { $this->normalizer = new TextNormalizer(); } public function addReference(ReferenceInterface $reference): void { $key = $this->normalizer->normalize($reference->getLabel()); $this->references[$key] = $reference; } public function contains(string $label): bool { $label = $this->normalizer->normalize($label); return isset($this->references[$label]); } public function getReference(string $label): ?ReferenceInterface { $label = $this->normalizer->normalize($label); if (!isset($this->references[$label])) { return null; } return $this->references[$label]; } public function listReferences(): iterable { return \array_values($this->references); } } 